"""
Detects a red-dyed water droplet using HSV color thresholding.
Handles fast-moving droplets with wider HSV range and larger search window.
"""
import cv2
import numpy as np


class DropletDetector:
    def __init__(self):
        # Widened HSV range to catch motion-blurred droplets
        # Original: S>=150, V>=50 — too strict for fast movement
        # Updated: S>=100, V>=30 — catches blurred/dim red
       
        self.lower_red_1 = np.array([0, 150, 50])
        self.upper_red_1 = np.array([10, 255, 200])
        self.lower_red_2 = np.array([170, 150, 50])
        self.upper_red_2 = np.array([180, 255, 200])

        # Larger search window for fast-moving droplets
        # 200px = 100px each direction (was 50px before)
        self.window_size = 200
        self.last_position = None

    def detect(self, image):
        if self.last_position is not None:
            u_prev, v_prev = self.last_position
            half = self.window_size // 2
            y1 = max(0, v_prev - half)
            y2 = min(image.shape[0], v_prev + half)
            x1 = max(0, u_prev - half)
            x2 = min(image.shape[1], u_prev + half)

            search_region = image[y1:y2, x1:x2]
            offset = (x1, y1)
        else:
            search_region = image
            offset = (0, 0)

        result = self._detect_in_region(search_region, offset)

        if result is not None:
            return result

        # Search window failed — try full board region before giving up
        if offset != (0, 0):
            result = self._detect_in_region(image, (0, 0))
            if result is not None:
                return result

        self.last_position = None
        return None

    def _detect_in_region(self, region, offset):
        """Detect red droplet in a given image region."""
        hsv = cv2.cvtColor(region, cv2.COLOR_BGR2HSV)
        mask1 = cv2.inRange(hsv, self.lower_red_1, self.upper_red_1)
        mask2 = cv2.inRange(hsv, self.lower_red_2, self.upper_red_2)
        mask = cv2.bitwise_or(mask1, mask2)

        kernel = np.ones((3, 3), np.uint8)
        mask = cv2.morphologyEx(mask, cv2.MORPH_OPEN, kernel)
        mask = cv2.morphologyEx(mask, cv2.MORPH_CLOSE, kernel)

        contours, _ = cv2.findContours(
            mask, cv2.RETR_EXTERNAL, cv2.CHAIN_APPROX_SIMPLE
        )

        if len(contours) == 0:
            return None

        largest = max(contours, key=cv2.contourArea)
        area = cv2.contourArea(largest)

        if area < 20 or area > 8000:
            return None

        M = cv2.moments(largest)
        if M['m00'] == 0:
            return None

        cx = int(M['m10'] / M['m00']) + offset[0]
        cy = int(M['m01'] / M['m00']) + offset[1]

        self.last_position = (cx, cy)
        return (cx, cy)

    def reset(self):
        self.last_position = None
